@SpringBootApplication
public class MainPlatformVSearchVectorStoreRagExample {

    public static void main(String[] args) {
        new SpringApplicationBuilder(MainPlatformVSearchVectorStoreRagExample.class)
                .web(WebApplicationType.NONE)
                .run(args)
                .close();
    }

    @Value("classpath:/rag/rag.txt")
    Resource ragDocument;

    @Bean
    public CommandLineRunner runner(ChatClient.Builder builder, VectorStore vectorStore) {
        return args -> {
            ChatClient chatClient = builder.defaultAdvisors(new QuestionAnswerAdvisor(vectorStore))
                    .build();

            List<String> documentIds = initializeVectorStore(vectorStore);

            String question = "What university John has finished?";
            String answer = chatClient.prompt().user(question).call().content();

            System.out.println(" - " + question);
            System.out.println(" - " + answer);
        };
    }

    @SneakyThrows
    private List<String> initializeVectorStore(VectorStore vectorStore) {
        String sourceText = ragDocument.getContentAsString(StandardCharsets.UTF_8);
        List<Document> documents =
                sourceText.lines().filter(s -> !s.isBlank()).map(Document::new).toList();
        vectorStore.add(documents);
        return documents.stream().map(Document::getId).toList();
    }
}
```
